import { NextResponse } from "next/server";import { getStripe } from "@/lib/stripe";
export async function POST(req){const body=await req.json();const stripe=getStripe();const appUrl=process.env.NEXT_PUBLIC_APP_URL||"http://localhost:3000";if(!stripe)return NextResponse.json({ok:false,mode:"placeholder",message:"Add STRIPE_SECRET_KEY to enable Stripe Connect vendor onboarding.",vendor:body.vendor});const account=await stripe.accounts.create({type:"express",capabilities:{card_payments:{requested:true},transfers:{requested:true}},business_type:"individual",metadata:{app:"GatherGenius",vendorName:body.vendor?.name||""}});const link=await stripe.accountLinks.create({account:account.id,refresh_url:`${appUrl}?vendor_onboard=refresh`,return_url:`${appUrl}?vendor_onboard=complete`,type:"account_onboarding"});return NextResponse.json({ok:true,message:"Stripe Connect onboarding link created.",url:link.url,accountId:account.id});}